mapper.update:
UPDATE book_stock
SET available_quantity = available_quantity - #{quantity},
    in_transit_quantity = in_transit_quantity + #{quantity},
    version = version + 1
WHERE book_id = #{bookId} AND branch_id = #{branchId} AND version = #{version}
  AND available_quantity >= #{quantity}

UPDATE book_stock
SET in_transit_quantity = in_transit_quantity - #{quantity},
    version = version + 1
WHERE book_id = #{bookId} AND branch_id = #{branchId} AND version = #{version}
  AND in_transit_quantity >= #{quantity}
